on conflict (slug) do update
set
  category_id = excluded.category_id,
  name = excluded.name,
  official_url = excluded.official_url,
  allergen_source_url = excluded.allergen_source_url,
  origin_source_url = excluded.origin_source_url,
  data_status = excluded.data_status,
  last_checked_at = excluded.last_checked_at,
  display_order = excluded.display_order,
  is_active = true;

on conflict (brand_id, source_type, url) do update
set
  title = excluded.title,
  checked_at = excluded.checked_at,
  note = excluded.note;

on conflict (slug) do update
set
  brand_id = excluded.brand_id,
  category_id = excluded.category_id,
  name = excluded.name,
  source_url = excluded.source_url,
  last_checked_at = excluded.last_checked_at,
  menu_status = excluded.menu_status,
  is_active = true;

on conflict (menu_id, allergen_id, presence_type) do update
set
  note = excluded.note,
  source_id = excluded.source_id;

commit;
